// cSpell:disable// ignore_for_file: type=lint, unused_field, prefer_const_constructors, prefer_const_literals_to_create_immutables, use_build_context_synchronously, avoid_printimport 'dart:io';import 'dart:convert';import 'package:flutter/material.dart';import 'package:flutter/services.dart';import 'package:firebase_auth/firebase_auth.dart';import 'package:cloud_firestore/cloud_firestore.dart';import 'package:intl/intl.dart';import 'package:url_launcher/url_launcher.dart';import 'package:flutter_local_notifications/flutter_local_notifications.dart';import 'package:timezone/timezone.dart' as tz;import 'package:timezone/data/latest.dart' as tz;import 'package:provider/provider.dart';import 'package:shared_preferences/shared_preferences.dart';import 'package:image_picker/image_picker.dart';import 'package:http/http.dart' as http;import 'theme_provider.dart';import 'login.dart';import 'admin_page.dart';class HomeScreen extends StatefulWidget {  const HomeScreen({super.key});  @override  State<HomeScreen> createState() => _HomeScreenState();}class _HomeScreenState extends State<HomeScreen> {  // --- QUẢN LÝ TRẠNG THÁI GIAO DIỆN (UI STATE) ---  int _currentIndex =      0; // Lưu vị trí tab đang chọn (0: Trang chủ, 1: Lịch hẹn, 2: Hồ sơ)  bool isVietnamese = true; // Cờ chuyển đổi ngôn ngữ Việt - Anh  // --- BỘ ĐIỀU KHIỂN NHẬP LIỆU (CONTROLLERS) ---  final ScrollController _scrollController = ScrollController();  final TextEditingController _searchController = TextEditingController();  final TextEditingController _nameController = TextEditingController();  final TextEditingController _phoneController = TextEditingController();  final TextEditingController _addressController = TextEditingController();  final TextEditingController _emailController = TextEditingController();  final TextEditingController _currentPasswordController =      TextEditingController();  final TextEditingController _newPasswordController = TextEditingController();  final TextEditingController _confirmPasswordController =      TextEditingController();  final TextEditingController _editNameController = TextEditingController();  // --- FIREBASE & HỆ THỐNG ---  final User? user = FirebaseAuth      .instance      .currentUser; // Lấy thông tin người dùng đang đăng nhập  String _userName = "Người dùng"; // Tên hiển thị người dùng  String _profileImagePath = ""; // Đường dẫn ảnh đại diện local  final FlutterLocalNotificationsPlugin flutterLocalNotificationsPlugin =      FlutterLocalNotificationsPlugin();  // --- HỆ THỐNG ĐA NGÔN NGỮ (LOCALIZATION) ---  Map<String, dynamic> get lang => {    'home': isVietnamese ? "Trang chủ" : "Home",    'booking': isVietnamese ? "Lịch hẹn" : "Appointment",    'profile': isVietnamese ? "Hồ sơ" : "Profile",    'welcome': isVietnamese ? "Chào bạn! 👋" : "Hello! 👋",    'find_doc': isVietnamese ? "Tìm bác sĩ" : "Find doctor",    'search_hint': isVietnamese ? "Tìm bác sĩ..." : "Search...",    'dept': isVietnamese ? "Chuyên khoa" : "Speciality",    'all': isVietnamese ? "Xem tất cả" : "See all",    'book_btn': isVietnamese ? "Đặt lịch ngay" : "Book now",    'my_booking': isVietnamese ? "Lịch hẹn của bạn" : "Your Appointments",    'no_booking': isVietnamese ? "Chưa có lịch hẹn nào." : "No appointments.",    'patient': isVietnamese ? "Người khám" : "Patient",    'phone': isVietnamese ? "SĐT" : "Phone",    'address': isVietnamese ? "Địa chỉ" : "Address",    'email': isVietnamese ? "Email" : "Email",    'change_pw': isVietnamese ? "Đổi mật khẩu" : "Password",    'logout': isVietnamese ? "Đăng xuất" : "Logout",    'call_hotline': isVietnamese ? "Hotline" : "Hotline",    'dark_mode': isVietnamese ? "Chế độ tối" : "Dark Mode",    'admin_panel': isVietnamese ? "Quản trị" : "Admin",    'select_slot': isVietnamese ? "Chọn giờ khám" : "Select slot",    'edit_name': isVietnamese ? "Đổi tên" : "Edit Name",    'enter_name': isVietnamese ? "Nhập tên mới" : "New name",    'cancel': isVietnamese ? "Hủy" : "Cancel",    'save': isVietnamese ? "Lưu" : "Save",    'name_success': isVietnamese ? "Thành công!" : "Success!",    'appt_details': isVietnamese ? "Chi tiết" : "Details",    'close': isVietnamese ? "Đóng" : "Close",    'current_pw': isVietnamese ? "Mật khẩu cũ" : "Current PW",    'new_pw': isVietnamese ? "Mật khẩu mới" : "New PW",    'confirm_pw': isVietnamese ? "Xác nhận" : "Confirm",    'pw_not_match': isVietnamese ? "Không khớp!" : "Not match!",    'pw_success': isVietnamese ? "Đã đổi!" : "Changed!",    'pw_error': isVietnamese ? "Lỗi!" : "Error!",    'fill_all': isVietnamese ? "Điền đủ thông tin!" : "Fill all!",    'back_hosp': isVietnamese ? "Đổi nơi khám" : "Change Hospital",    'select_hosp': isVietnamese ? "Chọn nơi khám" : "Select Hospital",  };  String? _selectedHospital; // Lưu bệnh viện đang chọn  String? _selectedDeptFilter; // Lưu chuyên khoa đang lọc  List<Map<String, dynamic>> bookedAppointments =      []; // Danh sách lịch hẹn từ Firestore  // Danh sách khung giờ khám cố định của hệ thống  final List<String> _timeSlots = [    "08:00",    "08:30",    "09:00",    "09:30",    "10:00",    "10:30",    "13:30",    "14:00",    "14:30",    "15:00",    "15:30",    "16:00",    "16:30",    "17:00",    "17:30",    "18:00",    "18:30",    "19:00",    "19:30",    "20:00",    "20:30",    "21:00",    "21:30",    "22:00",  ];  @override  void initState() {    super.initState();    _initNotifications(); // Khởi tạo thông báo    _loadAppState(); // Tải cấu hình đã lưu (ngôn ngữ, ảnh)    _fetchAppointments(); // Lấy lịch hẹn từ Firestore  }  @override  void dispose() {    // Giải phóng bộ nhớ khi không dùng đến các controller    _editNameController.dispose();    _currentPasswordController.dispose();    _newPasswordController.dispose();    _confirmPasswordController.dispose();    _nameController.dispose();    _phoneController.dispose();    _addressController.dispose();    _emailController.dispose();    super.dispose();  }  // --- KIỂM TRA ĐỊNH DẠNG EMAIL ---  bool _isValidEmail(String email) {    return RegExp(r'^[\w-\.]+@([\w-]+\.)+[\w-]{2,4}$').hasMatch(email);  }  // --- CHUYỂN ĐỔI TÊN CHUYÊN KHOA SANG TIẾNG ANH (MAPPING) ---  String _getDisplayName(String name) {    if (isVietnamese) return name;    String key = name.toLowerCase().trim();    key = key.replaceAll(RegExp(r'[àáạảãâầấậẩẫăằắặẳẵ]'), 'a');    key = key.replaceAll(RegExp(r'[èéẹẻẽêềếệểễ]'), 'e');    key = key.replaceAll(RegExp(r'[ìíịỉĩ]'), 'i');    key = key.replaceAll(RegExp(r'[òóọỏõôồốộổỗơờớợởỡ]'), 'o');    key = key.replaceAll(RegExp(r'[ùúụủũưừứựửữ]'), 'u');    key = key.replaceAll(RegExp(r'[ỳýỵỷỹ]'), 'y');    key = key.replaceAll(RegExp(r'[đ]'), 'd');    Map<String, String> translation = {      "tim mach": "Cardiology",      "mat": "Ophthalmology",      "nhi khoa": "Pediatrics",      "tam than": "Psychiatry",      "chinh hinh": "Orthopedics",      "noi khoa": "Internal Medicine",      "ngoai khoa": "Surgery",      "da lieu": "Dermatology",      "tai mui hong": "ENT",      "rang ham mat": "Dentistry",      "ung buou": "Oncology",      "phu khoa": "Gynecology",      "da khoa": "General Clinic",      "than": "Nephrology",      "tieu hoa": "Gastroenterology",    };    return translation[key] ?? name;  }  // --- TỰ ĐỘNG GÁN ICON THEO CHUYÊN KHOA ---  IconData _getIconForSpeciality(String name) {    name = name.toLowerCase();    if (name.contains("tim") || name.contains("mạch"))      return Icons.favorite_rounded;    if (name.contains("nhi") || name.contains("trẻ"))      return Icons.child_care_rounded;    if (name.contains("mắt")) return Icons.visibility_rounded;    if (name.contains("tâm thần") || name.contains("não"))      return Icons.psychology_rounded;    if (name.contains("chỉnh hình") || name.contains("xương"))      return Icons.healing_rounded;    if (name.contains("nội")) return Icons.medical_services_rounded;    if (name.contains("ngoại")) return Icons.biotech_rounded;    if (name.contains("da liễu")) return Icons.face_retouching_natural_rounded;    if (name.contains("tai") || name.contains("mũi") || name.contains("họng"))      return Icons.hearing_rounded;    if (name.contains("răng") || name.contains("hàm"))      return Icons.sentiment_satisfied_alt;    return Icons.label_important_outline;  }  // --- NHÓM LỊCH HẸN THEO THÁNG ---  Map<String, List<Map<String, dynamic>>> _groupAppointmentsByMonth() {    Map<String, List<Map<String, dynamic>>> groups = {};    List<Map<String, dynamic>> sortedList = List.from(bookedAppointments);    sortedList.sort(      (a, b) => (b['fullDateTime'] as DateTime).compareTo(        a['fullDateTime'] as DateTime,      ),    );    for (var app in sortedList) {      DateTime date = app['fullDateTime'] as DateTime;      String monthKey = isVietnamese          ? "Tháng ${DateFormat('MM, yyyy').format(date)}"          : DateFormat('MMMM yyyy').format(date);      if (groups[monthKey] == null) groups[monthKey] = [];      groups[monthKey]!.add(app);    }    return groups;  }  // --- TẢI TRẠNG THÁI ỨNG DỤNG (LOCAL STORAGE) ---  void _loadAppState() async {    final prefs = await SharedPreferences.getInstance();    setState(() {      isVietnamese = prefs.getBool('isVietnamese') ?? true;      _profileImagePath = prefs.getString('profileImagePath') ?? "";      _userName = (user?.displayName != null && user!.displayName!.isNotEmpty)          ? user!.displayName!          : (user?.email ?? "Người dùng");    });  }  // --- CHỨC NĂNG CHỌN ẢNH ĐẠI DIỆN ---  Future<void> _pickImage() async {    final ImagePicker picker = ImagePicker();    final XFile? image = await picker.pickImage(source: ImageSource.gallery);    if (image != null) {      final prefs = await SharedPreferences.getInstance();      await prefs.setString('profileImagePath', image.path);      setState(() {        _profileImagePath = image.path;      });    }  }  // --- CHỨC NĂNG ĐỔI TÊN HIỂN THỊ ---  Future<void> _editName() async {    _editNameController.text = _userName;    final String? newName = await showDialog<String>(      context: context,      builder: (ctx) => AlertDialog(        title: Text(lang['edit_name']),        content: TextField(          controller: _editNameController,          decoration: InputDecoration(hintText: lang['enter_name']),        ),        actions: [          TextButton(            onPressed: () => Navigator.pop(ctx),            child: Text(lang['cancel']),          ),          ElevatedButton(            onPressed: () => Navigator.pop(ctx, _editNameController.text),            child: Text(lang['save']),          ),        ],      ),    );    if (newName != null && newName.trim().isNotEmpty) {      await user?.updateDisplayName(newName.trim());      setState(() {        _userName = newName.trim();      });    }  }  // --- CHỨC NĂNG ĐỔI MẬT KHẨU ---  Future<void> _showChangePasswordDialog() async {    _currentPasswordController.clear();    _newPasswordController.clear();    _confirmPasswordController.clear();    await showDialog(      context: context,      builder: (ctx) => AlertDialog(        title: Text(lang['change_pw']),        content: Column(          mainAxisSize: MainAxisSize.min,          children: [            TextField(              controller: _currentPasswordController,              obscureText: true,              decoration: InputDecoration(labelText: lang['current_pw']),            ),            TextField(              controller: _newPasswordController,              obscureText: true,              decoration: InputDecoration(labelText: lang['new_pw']),            ),            TextField(              controller: _confirmPasswordController,              obscureText: true,              decoration: InputDecoration(labelText: lang['confirm_pw']),            ),          ],        ),        actions: [          TextButton(            onPressed: () => Navigator.pop(ctx),            child: Text(lang['cancel']),          ),          ElevatedButton(            onPressed: () async {              try {                AuthCredential credential = EmailAuthProvider.credential(                  email: user!.email!,                  password: _currentPasswordController.text,                );                await user!.reauthenticateWithCredential(credential);                await user!.updatePassword(_newPasswordController.text);                Navigator.pop(ctx);              } catch (e) {                print(e);              }            },            child: Text(lang['save']),          ),        ],      ),    );  }  // --- LẤY DỮ LIỆU LỊCH HẸN TỪ FIRESTORE ---  void _fetchAppointments() async {    if (user == null) return;    try {      final snapshot = await FirebaseFirestore.instance          .collection('appointments')          .where('userId', isEqualTo: user?.uid)          .get();      final List<Map<String, dynamic>> loadedData = snapshot.docs.map((doc) {        final data = doc.data();        return {          'id': doc.id,          'name': (data['doctorName'] ?? 'Bác sĩ').toString(),          'image': (data['image'] ?? 'assets/images/logo.png').toString(),          'patient': (data['patientName'] ?? 'Bệnh nhân').toString(),          'phone': (data['patientPhone'] ?? '').toString(),          'address': (data['patientAddress'] ?? '').toString(),          'email': (data['patientEmail'] ?? '').toString(),          'hospital': (data['hospital'] ?? 'Bệnh viện').toString(),          'date': (data['date'] ?? '').toString(),          'time': (data['time'] ?? '').toString(),          'dept': (data['dept'] ?? '').toString(),          'fullDateTime': data['fullDateTime'] != null              ? DateTime.parse(data['fullDateTime'].toString())              : DateTime.now(),        };      }).toList();      setState(() {        bookedAppointments = loadedData;      });    } catch (e) {      debugPrint("Lỗi tải lịch hẹn: $e");    }  }  // --- KHỞI TẠO THÔNG BÁO LOCAL ---  void _initNotifications() async {    const AndroidInitializationSettings initializationSettingsAndroid =        AndroidInitializationSettings('@mipmap/ic_launcher');    const InitializationSettings initializationSettings =        InitializationSettings(android: initializationSettingsAndroid);    await flutterLocalNotificationsPlugin.initialize(initializationSettings);    tz.initializeTimeZones();  }  // --- HIỂN THỊ THÔNG BÁO PUSH LOCAL ---  Future<void> _showNotification(    String patientName,    String doctorName,    String time,  ) async {    const AndroidNotificationDetails androidPlatformChannelSpecifics =        AndroidNotificationDetails(          'mediapp_booking_channel',          'Thông báo Mediapp',          importance: Importance.max,          priority: Priority.high,        );    const NotificationDetails platformChannelSpecifics = NotificationDetails(      android: androidPlatformChannelSpecifics,    );    await flutterLocalNotificationsPlugin.show(      DateTime.now().millisecond,      isVietnamese          ? 'Mediapp: Đặt lịch thành công! ✅'          : 'Mediapp: Booking Success! ✅',      'Bệnh nhân $patientName có lịch với $doctorName vào $time',      platformChannelSpecifics,    );  }  // --- THỰC HIỆN CUỘC GỌI HOTLINE ---  Future<void> _makePhoneCall(String phoneNumber) async {    final Uri launchUri = Uri(scheme: 'tel', path: phoneNumber);    if (await canLaunchUrl(launchUri)) {      await launchUrl(launchUri);    }  }  // --- QUY TRÌNH ĐẶT LỊCH KHÁM (SỬA LỖI ẨN GIỜ ĐÃ ĐẶT) ---  Future<void> _bookDoctor(Map<String, dynamic> doc) async {    final DateTime? d = await showDatePicker(      context: context,      initialDate: DateTime.now(),      firstDate: DateTime.now(),      lastDate: DateTime(2027),    );    if (d == null) return;    String dateStr = DateFormat('dd/MM/yyyy').format(d);    // 1. Hiển thị loading và kiểm tra lịch trùng trên Firestore    showDialog(      context: context,      barrierDismissible: false,      builder: (ctx) => const Center(child: CircularProgressIndicator()),    );    List<String> takenSlots = [];    try {      final snapshot = await FirebaseFirestore.instance          .collection('appointments')          .where('doctorName', isEqualTo: doc['name'].toString().trim())          .where('date', isEqualTo: dateStr.trim())          .get();      for (var element in snapshot.docs) {        takenSlots.add(element.data()['time'].toString().trim());      }    } catch (e) {      debugPrint("Lỗi tải ca khám: $e");    }    if (mounted) Navigator.of(context, rootNavigator: true).pop();    _nameController.clear();    _phoneController.clear();    _addressController.clear();    _emailController.clear();    String? selectedTime;    if (!mounted) return;    // 2. Hiển thị giao diện chọn giờ và nhập thông tin (BottomSheet)    final bool? confirmed = await showModalBottomSheet<bool>(      context: context,      isScrollControlled: true,      backgroundColor: Colors.transparent,      builder: (ctx) => StatefulBuilder(        builder: (context, setModalState) {          bool isFormValid =              selectedTime != null &&              _nameController.text.trim().isNotEmpty &&              _phoneController.text.trim().length >= 10 &&              _addressController.text.trim().isNotEmpty &&              _isValidEmail(_emailController.text.trim());          return Padding(            padding: EdgeInsets.only(              bottom: MediaQuery.of(ctx).viewInsets.bottom,            ),            child: Container(              decoration: BoxDecoration(                color: Theme.of(context).scaffoldBackgroundColor,                borderRadius: const BorderRadius.vertical(                  top: Radius.circular(30),                ),              ),              child: SingleChildScrollView(                padding: const EdgeInsets.all(25),                child: Column(                  mainAxisSize: MainAxisSize.min,                  crossAxisAlignment: CrossAxisAlignment.start,                  children: [                    Center(                      child: Container(                        width: 40,                        height: 5,                        decoration: BoxDecoration(                          color: Colors.grey[300],                          borderRadius: BorderRadius.circular(10),                        ),                      ),                    ),                    const SizedBox(height: 20),                    Text(                      "${lang['select_slot']} ($dateStr)",                      style: const TextStyle(                        fontSize: 18,                        fontWeight: FontWeight.bold,                      ),                    ),                    const SizedBox(height: 15),                    // Render các khung giờ, ẩn (khóa) những giờ đã có người đặt (takenSlots)                    Wrap(                      spacing: 10,                      runSpacing: 10,                      children: _timeSlots.map((time) {                        bool isTaken = takenSlots.contains(time.trim());                        bool isSelected = selectedTime == time;                        return ChoiceChip(                          label: Text(                            time,                            style: TextStyle(                              color: isTaken                                  ? Colors.grey                                  : (isSelected ? Colors.white : null),                              decoration: isTaken                                  ? TextDecoration.lineThrough                                  : null,                            ),                          ),                          selected: isSelected,                          onSelected: isTaken                              ? null                              : (selected) {                                  setModalState(() => selectedTime = time);                                },                          selectedColor: Colors.blue,                          disabledColor: Colors.grey.shade200,                        );                      }).toList(),                    ),                    const SizedBox(height: 25),                    _buildBookingTextField(                      controller: _nameController,                      label: lang['patient'],                      icon: Icons.person,                      onChanged: (v) => setModalState(() {}),                    ),                    _buildBookingTextField(                      controller: _phoneController,                      label: lang['phone'],                      icon: Icons.phone,                      keyboardType: TextInputType.number,                      inputFormatters: [                        FilteringTextInputFormatter.digitsOnly,                        LengthLimitingTextInputFormatter(11),                      ],                      onChanged: (v) => setModalState(() {}),                    ),                    _buildBookingTextField(                      controller: _addressController,                      label: lang['address'],                      icon: Icons.location_on,                      onChanged: (v) => setModalState(() {}),                    ),                    _buildBookingTextField(                      controller: _emailController,                      label: lang['email'],                      icon: Icons.email,                      keyboardType: TextInputType.emailAddress,                      onChanged: (v) => setModalState(() {}),                    ),                    const SizedBox(height: 25),                    SizedBox(                      width: double.infinity,                      height: 55,                      child: ElevatedButton(                        onPressed: isFormValid                            ? () => Navigator.pop(ctx, true)                            : null,                        style: ElevatedButton.styleFrom(                          backgroundColor: Colors.blue,                          shape: RoundedRectangleBorder(                            borderRadius: BorderRadius.circular(15),                          ),                        ),                        child: Text(                          lang['book_btn'],                          style: const TextStyle(                            color: Colors.white,                            fontWeight: FontWeight.bold,                            fontSize: 16,                          ),                        ),                      ),                    ),                  ],                ),              ),            ),          );        },      ),    );    // 3. Thực hiện lưu lịch hẹn vào Firestore và đồng bộ Google Sheets    if (confirmed == true && selectedTime != null) {      try {        DateTime selDT = DateTime(          d.year,          d.month,          d.day,          int.parse(selectedTime!.split(":")[0]),          int.parse(selectedTime!.split(":")[1]),        );        await FirebaseFirestore.instance.collection('appointments').add({          'userId': user?.uid,          'doctorName': doc['name'],          'patientName': _nameController.text.trim(),          'patientPhone': _phoneController.text.trim(),          'patientAddress': _addressController.text.trim(),          'patientEmail': _emailController.text.trim(),          'hospital': _selectedHospital,          'image': doc['image'],          'date': dateStr,          'time': selectedTime,          'dept': doc['dept'],          'fullDateTime': selDT.toIso8601String(),          'createdAt': FieldValue.serverTimestamp(),        });        // Tích hợp API Google Apps Script đẩy dữ liệu sang Google Sheets        try {          const String googleScriptUrl =              "https://script.google.com/macros/s/AKfycbxM62i0w6_04AfIdE-qBud7t4iS9afdWBqRtAxok40uGIgYHQV2ue2-lSApUAdgo-kxJQ/exec";          http.post(            Uri.parse(googleScriptUrl),            body: jsonEncode({              'patientName': _nameController.text.trim(),              'doctorName': doc['name'],              'date': dateStr,              'time': selectedTime,              'hospital': _selectedHospital,            }),          );        } catch (e) {          print("Lỗi Sheets: $e");        }        _fetchAppointments(); // Cập nhật lại UI danh sách lịch hẹn        await _showNotification(          _nameController.text,          doc['name']!,          selectedTime!,        ); // Bắn thông báo        if (mounted)          ScaffoldMessenger.of(context).showSnackBar(            SnackBar(              content: Text(                isVietnamese ? "Đặt lịch thành công!" : "Booking success!",              ),              backgroundColor: Colors.green,            ),          );      } catch (e) {        debugPrint("Lỗi đặt lịch: $e");      }    }  }  // --- WIDGET XÂY DỰNG Ô NHẬP LIỆU ---  Widget _buildBookingTextField({    required TextEditingController controller,    required String label,    required IconData icon,    TextInputType keyboardType = TextInputType.text,    List<TextInputFormatter>? inputFormatters,    required Function(String) onChanged,  }) {    return Padding(      padding: const EdgeInsets.only(bottom: 15),      child: TextField(        controller: controller,        onChanged: onChanged,        keyboardType: keyboardType,        inputFormatters: inputFormatters,        decoration: InputDecoration(          labelText: label,          prefixIcon: Icon(icon),          filled: true,          fillColor: Theme.of(context).brightness == Brightness.dark              ? Colors.grey[800]              : Colors.grey[100],          border: OutlineInputBorder(            borderRadius: BorderRadius.circular(15),            borderSide: BorderSide.none,          ),        ),      ),    );  }  // --- TAB 1: TRANG CHỦ (DANH SÁCH BỆNH VIỆN & BÁC SĨ) ---  Widget _buildHomeTab() {    return SingleChildScrollView(      controller: _scrollController,      padding: const EdgeInsets.symmetric(horizontal: 20),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          const SizedBox(height: 10),          Text(            lang['welcome'].toString(),            style: const TextStyle(color: Colors.grey),          ),          if (_selectedHospital == null) ...[            Text(              lang['select_hosp'].toString(),              style: const TextStyle(fontSize: 26, fontWeight: FontWeight.bold),            ),            const SizedBox(height: 8),            _buildHospitalGrid(),          ] else ...[            Row(              mainAxisAlignment: MainAxisAlignment.spaceBetween,              children: [                Expanded(                  child: Text(                    _selectedHospital.toString(),                    style: const TextStyle(                      fontSize: 22,                      fontWeight: FontWeight.bold,                      color: Colors.blue,                    ),                  ),                ),                TextButton.icon(                  onPressed: () => setState(() {                    _selectedHospital = null;                    _selectedDeptFilter = null;                  }),                  icon: const Icon(Icons.swap_horiz, size: 18),                  label: Text(lang['back_hosp'].toString()),                ),              ],            ),            const SizedBox(height: 15),            _buildSearchBar(),            const SizedBox(height: 20),            _buildCategorySection(),            _buildDoctorGrid(),          ],          const SizedBox(height: 40),        ],      ),    );  }  // --- GRID HIỂN THỊ BỆNH VIỆN ---  Widget _buildHospitalGrid() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('hospitals')          .orderBy('createdAt', descending: false)          .snapshots(),      builder: (context, snapshot) {        if (!snapshot.hasData)          return const Center(child: CircularProgressIndicator());        final docs = snapshot.data!.docs;        return ListView.builder(          shrinkWrap: true,          physics: const NeverScrollableScrollPhysics(),          itemCount: docs.length,          itemBuilder: (context, i) {            String hospName = (docs[i]['name'] ?? 'Bệnh viện').toString();            return Container(              margin: const EdgeInsets.only(bottom: 15),              child: InkWell(                onTap: () => setState(() => _selectedHospital = hospName),                borderRadius: BorderRadius.circular(20),                child: Container(                  padding: const EdgeInsets.all(20),                  decoration: BoxDecoration(                    gradient: LinearGradient(                      colors: [Colors.blue.shade400, Colors.blue.shade700],                      begin: Alignment.topLeft,                      end: Alignment.bottomRight,                    ),                    borderRadius: BorderRadius.circular(20),                  ),                  child: Row(                    children: [                      const Icon(                        Icons.local_hospital,                        color: Colors.white,                        size: 30,                      ),                      const SizedBox(width: 20),                      Expanded(                        child: Text(                          hospName,                          style: const TextStyle(                            color: Colors.white,                            fontWeight: FontWeight.bold,                            fontSize: 18,                          ),                        ),                      ),                      const Icon(                        Icons.arrow_forward_ios,                        color: Colors.white,                        size: 18,                      ),                    ],                  ),                ),              ),            );          },        );      },    );  }  // --- THANH TÌM KIẾM ---  Widget _buildSearchBar() => TextField(    decoration: InputDecoration(      hintText: lang['search_hint'].toString(),      prefixIcon: const Icon(Icons.search),      filled: true,      border: OutlineInputBorder(        borderRadius: BorderRadius.circular(15),        borderSide: BorderSide.none,      ),    ),  );  // --- LỌC CHUYÊN KHOA ---  Widget _buildCategorySection() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('specialities')          .orderBy('createdAt', descending: false)          .snapshots(),      builder: (context, snapshot) {        if (!snapshot.hasData) return const SizedBox();        final specs = snapshot.data!.docs;        return SizedBox(          height: 100,          child: ListView.builder(            scrollDirection: Axis.horizontal,            itemCount: specs.length,            itemBuilder: (context, i) {              String name = (specs[i]['name'] ?? 'Chuyên khoa').toString();              return _catItem(                _getIconForSpeciality(name),                _getDisplayName(name),                name,              );            },          ),        );      },    );  }  Widget _catItem(IconData icon, String label, String deptKey) =>      GestureDetector(        onTap: () => setState(() => _selectedDeptFilter = deptKey),        child: Padding(          padding: const EdgeInsets.only(right: 20),          child: Column(            children: [              CircleAvatar(                radius: 28,                backgroundColor: _selectedDeptFilter == deptKey                    ? Colors.blue                    : Colors.blue.withOpacity(0.1),                child: Icon(                  icon,                  color: _selectedDeptFilter == deptKey                      ? Colors.white                      : Colors.blue,                  size: 28,                ),              ),              const SizedBox(height: 8),              Text(                label,                style: TextStyle(                  fontSize: 11,                  fontWeight: _selectedDeptFilter == deptKey                      ? FontWeight.bold                      : FontWeight.w500,                  color: _selectedDeptFilter == deptKey ? Colors.blue : null,                ),              ),            ],          ),        ),      );  // --- GRID HIỂN THỊ DANH SÁCH BÁC SĨ ---  Widget _buildDoctorGrid() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('doctors')          .orderBy('createdAt', descending: true)          .snapshots(),      builder: (context, snapshot) {        if (!snapshot.hasData)          return const Center(child: CircularProgressIndicator());        final List<DocumentSnapshot> allDocs = snapshot.data!.docs;        final filteredDocs = allDocs.where((doc) {          final data = doc.data() as Map<String, dynamic>;          bool matchesHosp = data['hospital'] == _selectedHospital;          bool matchesDept =              (_selectedDeptFilter == null) ||              (data['dept'] == _selectedDeptFilter);          return matchesHosp && matchesDept;        }).toList();        return GridView.builder(          shrinkWrap: true,          physics: const NeverScrollableScrollPhysics(),          gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(            crossAxisCount: 2,            mainAxisSpacing: 15,            crossAxisSpacing: 15,            childAspectRatio: 0.8,          ),          itemCount: filteredDocs.length,          itemBuilder: (ctx, i) {            final data = filteredDocs[i].data() as Map<String, dynamic>;            final doc = {              'id': filteredDocs[i].id,              'name': (data['name'] ?? 'Bác sĩ').toString(),              'dept': (data['dept'] ?? '').toString(),              'hospital': (data['hospital'] ?? '').toString(),              'image': (data['image'] ?? 'assets/images/logo.png').toString(),            };            bool isAsset = !doc['image']!.startsWith('http');            return GestureDetector(              onTap: () => _bookDoctor(doc),              child: Container(                decoration: BoxDecoration(                  color: Theme.of(context).cardTheme.color ?? Colors.white,                  borderRadius: BorderRadius.circular(15),                  border: Border.all(color: Colors.grey.withOpacity(0.1)),                ),                child: Column(                  children: [                    Expanded(                      child: ClipRRect(                        borderRadius: const BorderRadius.vertical(                          top: Radius.circular(15),                        ),                        child: isAsset                            ? Image.asset(                                doc['image']!,                                fit: BoxFit.cover,                                width: double.infinity,                              )                            : Image.network(                                doc['image']!,                                fit: BoxFit.cover,                                width: double.infinity,                              ),                      ),                    ),                    Padding(                      padding: const EdgeInsets.all(8),                      child: Column(                        children: [                          Text(                            doc['name']!,                            style: const TextStyle(                              fontWeight: FontWeight.bold,                              fontSize: 12,                            ),                            textAlign: TextAlign.center,                          ),                          Text(                            _getDisplayName(doc['dept']!),                            style: const TextStyle(                              color: Colors.grey,                              fontSize: 10,                              fontStyle: FontStyle.italic,                            ),                          ),                          const SizedBox(height: 4),                          Text(                            lang['book_btn'].toString(),                            style: const TextStyle(                              color: Colors.blue,                              fontSize: 10,                              fontWeight: FontWeight.bold,                            ),                          ),                        ],                      ),                    ),                  ],                ),              ),            );          },        );      },    );  }  // --- TAB 2: LỊCH SỬ LỊCH HẸN ---  Widget _buildHistoryTab() {    final groupedData = _groupAppointmentsByMonth();    return Padding(      padding: const EdgeInsets.all(20),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Text(            lang['my_booking'].toString(),            style: const TextStyle(              fontSize: 22,              fontWeight: FontWeight.bold,              color: Colors.blue,            ),          ),          const SizedBox(height: 15),          Expanded(            child: bookedAppointments.isEmpty                ? Center(child: Text(lang['no_booking'].toString()))                : ListView.builder(                    itemCount: groupedData.length,                    itemBuilder: (context, index) {                      String month = groupedData.keys.elementAt(index);                      List<Map<String, dynamic>> apps = groupedData[month]!;                      return Column(                        crossAxisAlignment: CrossAxisAlignment.start,                        children: [                          Padding(                            padding: const EdgeInsets.symmetric(vertical: 10),                            child: Row(                              children: [                                Container(                                  padding: const EdgeInsets.symmetric(                                    horizontal: 12,                                    vertical: 6,                                  ),                                  decoration: BoxDecoration(                                    color: Colors.blue.withOpacity(0.1),                                    borderRadius: BorderRadius.circular(20),                                  ),                                  child: Text(                                    month,                                    style: const TextStyle(                                      fontWeight: FontWeight.bold,                                      color: Colors.blue,                                      fontSize: 14,                                    ),                                  ),                                ),                                const Expanded(child: Divider(indent: 10)),                              ],                            ),                          ),                          ...apps.map(                            (app) => Card(                              margin: const EdgeInsets.only(bottom: 10),                              shape: RoundedRectangleBorder(                                borderRadius: BorderRadius.circular(15),                              ),                              child: ListTile(                                onTap: () => _showAppointmentDetails(app),                                leading: CircleAvatar(                                  backgroundImage:                                      app['image'].startsWith('http')                                      ? NetworkImage(app['image'])                                      : AssetImage(app['image'])                                            as ImageProvider,                                ),                                title: Text(                                  app['name'].toString(),                                  style: const TextStyle(                                    fontWeight: FontWeight.bold,                                  ),                                ),                                subtitle: Text(                                  "${lang['patient']}: ${app['patient']}\n📅 ${app['date']} - ${app['time']}",                                  style: const TextStyle(fontSize: 12),                                ),                                isThreeLine: true,                                trailing: IconButton(                                  icon: const Icon(                                    Icons.delete_outline,                                    color: Colors.redAccent,                                  ),                                  onPressed: () async {                                    await FirebaseFirestore.instance                                        .collection('appointments')                                        .doc(app['id'])                                        .delete();                                    _fetchAppointments();                                  },                                ),                              ),                            ),                          ),                        ],                      );                    },                  ),          ),        ],      ),    );  }  // --- HIỂN THỊ CHI TIẾT LỊCH HẸN (POPUP) ---  void _showAppointmentDetails(Map<String, dynamic> app) {    showModalBottomSheet(      context: context,      isScrollControlled: true,      shape: const RoundedRectangleBorder(        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),      ),      builder: (ctx) => SafeArea(        child: Container(          padding: const EdgeInsets.all(20),          constraints: BoxConstraints(            maxHeight: MediaQuery.of(context).size.height * 0.85,          ),          child: Column(            mainAxisSize: MainAxisSize.min,            crossAxisAlignment: CrossAxisAlignment.start,            children: [              Center(                child: Container(                  width: 40,                  height: 5,                  decoration: BoxDecoration(                    color: Colors.grey[300],                    borderRadius: BorderRadius.circular(10),                  ),                ),              ),              const SizedBox(height: 20),              Text(                lang['appt_details'].toString(),                style: const TextStyle(                  fontSize: 20,                  fontWeight: FontWeight.bold,                  color: Colors.blue,                ),              ),              const SizedBox(height: 15),              Flexible(                child: SingleChildScrollView(                  child: Column(                    children: [                      _detailRow(                        Icons.medical_services,                        "Bác sĩ",                        app['name'].toString(),                      ),                      _detailRow(                        Icons.category,                        lang['dept'].toString(),                        _getDisplayName(app['dept'].toString()),                      ),                      _detailRow(                        Icons.local_hospital,                        "Bệnh viện",                        app['hospital'].toString(),                      ),                      _detailRow(                        Icons.access_time,                        "Thời gian",                        "${app['time']} - ${app['date']}",                      ),                      const Divider(height: 30),                      _detailRow(                        Icons.person,                        lang['patient'].toString(),                        app['patient'].toString(),                      ),                      if (app['phone'].toString().isNotEmpty)                        _detailRow(                          Icons.phone,                          lang['phone'].toString(),                          app['phone'].toString(),                        ),                      if (app['email'].toString().isNotEmpty)                        _detailRow(                          Icons.email,                          lang['email'].toString(),                          app['email'].toString(),                        ),                    ],                  ),                ),              ),              const SizedBox(height: 20),              SizedBox(                width: double.infinity,                height: 50,                child: ElevatedButton(                  onPressed: () => Navigator.pop(ctx),                  style: ElevatedButton.styleFrom(                    backgroundColor: Colors.blue,                    shape: RoundedRectangleBorder(                      borderRadius: BorderRadius.circular(15),                    ),                  ),                  child: Text(                    lang['close'].toString(),                    style: const TextStyle(                      color: Colors.white,                      fontWeight: FontWeight.bold,                      fontSize: 16,                    ),                  ),                ),              ),            ],          ),        ),      ),    );  }  Widget _detailRow(IconData icon, String title, String value) => Padding(    padding: const EdgeInsets.only(bottom: 12),    child: Row(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Icon(icon, size: 20, color: Colors.grey),        const SizedBox(width: 10),        Expanded(          child: Column(            crossAxisAlignment: CrossAxisAlignment.start,            children: [              Text(                title,                style: const TextStyle(fontSize: 12, color: Colors.grey),              ),              Text(                value,                style: const TextStyle(                  fontSize: 15,                  fontWeight: FontWeight.w500,                ),                softWrap: true,              ),            ],          ),        ),      ],    ),  );  // --- TAB 3: HỒ SƠ CÁ NHÂN & CÀI ĐẶT ---  Widget _buildProfileTab() {    final themeProvider = Provider.of<ThemeProvider>(context);    final isDark = themeProvider.isDarkMode;    return SingleChildScrollView(      padding: const EdgeInsets.all(20),      child: Column(        children: [          Container(            padding: const EdgeInsets.all(20),            decoration: BoxDecoration(              color: isDark ? Colors.grey[800] : Colors.white,              borderRadius: BorderRadius.circular(25),            ),            child: Column(              children: [                Stack(                  alignment: Alignment.bottomRight,                  children: [                    Container(                      decoration: BoxDecoration(                        shape: BoxShape.circle,                        border: Border.all(                          color: Colors.blue.shade100,                          width: 4,                        ),                      ),                      child: CircleAvatar(                        radius: 50,                        backgroundColor: Colors.blue.shade50,                        backgroundImage: _profileImagePath.isNotEmpty                            ? FileImage(File(_profileImagePath))                            : null,                        child: _profileImagePath.isEmpty                            ? Icon(                                Icons.person,                                size: 50,                                color: Colors.blue.shade300,                              )                            : null,                      ),                    ),                    GestureDetector(                      onTap: _pickImage,                      child: Container(                        padding: const EdgeInsets.all(8),                        decoration: BoxDecoration(                          color: Colors.blue,                          shape: BoxShape.circle,                          border: Border.all(color: Colors.white, width: 2),                        ),                        child: const Icon(                          Icons.camera_alt,                          size: 16,                          color: Colors.white,                        ),                      ),                    ),                  ],                ),                const SizedBox(height: 15),                Row(                  mainAxisAlignment: MainAxisAlignment.center,                  children: [                    Text(                      _userName.toString(),                      style: const TextStyle(                        fontSize: 22,                        fontWeight: FontWeight.bold,                      ),                    ),                    const SizedBox(width: 8),                    GestureDetector(                      onTap: _editName,                      child: const Icon(                        Icons.edit_square,                        color: Colors.blue,                        size: 18,                      ),                    ),                  ],                ),                Text(                  (user?.email ?? "User").toString(),                  style: const TextStyle(fontSize: 14, color: Colors.grey),                ),              ],            ),          ),          const SizedBox(height: 30),          Container(            decoration: BoxDecoration(              color: isDark ? Colors.grey[800] : Colors.white,              borderRadius: BorderRadius.circular(25),            ),            child: Column(              children: [                ListTile(                  leading: Icon(                    isDark ? Icons.dark_mode : Icons.light_mode,                    color: Colors.amber,                  ),                  title: Text(lang['dark_mode'].toString()),                  trailing: Switch(                    value: isDark,                    activeColor: Colors.blue,                    onChanged: (v) => themeProvider.toggleTheme(),                  ),                ),                if (user?.email == "quocthang15082004@gmail.com")                  _buildModernMenu(                    Icons.admin_panel_settings,                    lang['admin_panel'].toString(),                    Colors.indigo,                    () => Navigator.push(                      context,                      MaterialPageRoute(                        builder: (c) => AdminPage(isVietnamese: isVietnamese),                      ),                    ),                  ),                _buildModernMenu(                  Icons.lock_outline,                  lang['change_pw'].toString(),                  Colors.green,                  () => _showChangePasswordDialog(),                ),                _buildModernMenu(                  Icons.logout,                  lang['logout'].toString(),                  Colors.redAccent,                  () async {                    await FirebaseAuth.instance.signOut();                    Navigator.pushReplacement(                      context,                      MaterialPageRoute(builder: (c) => Login()),                    );                  },                  isRed: true,                ),              ],            ),          ),        ],      ),    );  }  Widget _buildModernMenu(    IconData icon,    String title,    Color iconColor,    VoidCallback onTap, {    bool isRed = false,  }) => ListTile(    leading: Icon(icon, color: isRed ? Colors.redAccent : iconColor),    title: Text(      title,      style: TextStyle(color: isRed ? Colors.redAccent : null),    ),    trailing: const Icon(Icons.arrow_forward_ios, size: 16),    onTap: onTap,  );  // --- HÀM ĐIỀU HƯỚNG TAB ---  Widget _getBody() {    switch (_currentIndex) {      case 0:        return _buildHomeTab();      case 1:        return _buildHistoryTab();      case 2:        return _buildProfileTab();      default:        return _buildHomeTab();    }  }  @override  Widget build(BuildContext context) {    return Scaffold(      appBar: AppBar(        title: const Text(          "Mediapp",          style: TextStyle(color: Colors.blue, fontWeight: FontWeight.bold),        ),        backgroundColor: Theme.of(context).appBarTheme.backgroundColor,        elevation: 0,        actions: [          IconButton(            icon: const Icon(Icons.phone, color: Colors.red),            onPressed: () => _makePhoneCall("19001234"),          ),          TextButton(            onPressed: () async {              setState(() => isVietnamese = !isVietnamese);              final prefs = await SharedPreferences.getInstance();              await prefs.setBool('isVietnamese', isVietnamese);            },            child: Text(              isVietnamese ? "EN" : "VN",              style: const TextStyle(                color: Colors.blue,                fontWeight: FontWeight.bold,              ),            ),          ),        ],      ),      body: _getBody(),      bottomNavigationBar: BottomNavigationBar(        currentIndex: _currentIndex,        onTap: (v) => setState(() => _currentIndex = v),        selectedItemColor: Colors.blue,        unselectedItemColor: Colors.grey,        type: BottomNavigationBarType.fixed,        items: [          BottomNavigationBarItem(            icon: const Icon(Icons.home),            label: lang['home'].toString(),          ),          BottomNavigationBarItem(            icon: const Icon(Icons.calendar_today),            label: lang['booking'].toString(),          ),          BottomNavigationBarItem(            icon: const Icon(Icons.person),            label: lang['profile'].toString(),          ),        ],      ),    );  }}